'use client';

import { usePathname } from 'next/navigation';
import { useLanguage } from '@/context/LanguageContext';
import { Globe, MessageSquare, Home, Tag, Users, ShieldCheck } from 'lucide-react';
import { motion } from 'framer-motion';
import Dock from '@/components/ui/Dock';
import Logo from '@/components/ui/Logo';
import Link from 'next/link';

export default function Navbar() {
  const { language, setLanguage, t } = useLanguage();
  const pathname = usePathname();

  const toggleLanguage = () => {
    setLanguage(language === 'id' ? 'en' : 'id');
  };

  const dockItems = [
    {
      label: 'Home',
      href: '/',
      icon: <Home size={18} />,
      active: pathname === '/',
    },
    {
      label: t.nav.pricelist,
      href: '/pricelist',
      icon: <Tag size={18} />,
      active: pathname === '/pricelist',
    },
    {
      label: t.nav.contact,
      href: '/contact',
      icon: <MessageSquare size={18} />,
      active: pathname === '/contact',
    },
    {
      label: t.nav.partners || 'Partners',
      href: '/partners',
      icon: <Users size={18} />,
      active: pathname === '/partners',
    },
  ];

  return (
    <>
      <div className="fixed bottom-6 inset-x-0 z-50 flex justify-center px-4 pointer-events-none">
        <motion.div 
          initial={{ y: 100, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ duration: 0.8, ease: "circOut" }}
          className="flex items-end gap-1.5 md:gap-2 pointer-events-auto max-w-full"
        >
          {/* Logo - Small version for mobile */}
          <div className="flex items-center justify-center w-12 h-12 md:w-14 md:h-14 rounded-xl md:rounded-2xl bg-white/80 backdrop-blur-3xl border border-black/5 shadow-[0_20px_50px_rgba(0,0,0,0.05)] overflow-hidden group shrink-0">
            <Link href="/">
              <Logo variant="icon" className="scale-[0.6] md:scale-90 group-hover:scale-100 transition-transform duration-500" />
            </Link>
          </div>

          <div className="w-[1px] h-8 md:h-10 bg-black/5 self-center mx-0.5" />

          {/* Main Navigation Dock */}
          <Dock 
            items={dockItems} 
            magnification={65}
            distance={140}
            baseItemSize={44}
            className="shrink min-w-0"
          />

          <div className="w-[1px] h-8 md:h-10 bg-black/5 self-center mx-0.5" />

          {/* Actions Dock */}
          <div className="flex items-center gap-1 md:gap-2 p-1.5 md:p-2 rounded-xl md:rounded-2xl bg-white/80 backdrop-blur-3xl border border-black/5 shadow-[0_20px_50px_rgba(0,0,0,0.05)] h-[60px] md:h-[68px] shrink-0">
            <button
              onClick={toggleLanguage}
              className="w-11 h-11 md:w-12 md:h-12 flex flex-col items-center justify-center rounded-lg md:rounded-xl bg-black/5 border border-black/5 text-black/30 hover:bg-brand-blue/10 hover:text-brand-blue hover:border-brand-blue/20 transition-all duration-500 group"
            >
              <Globe size={13} className="group-hover:rotate-12 transition-transform" />
              <span className="text-[6px] md:text-[7px] font-black mt-0.5">{language.toUpperCase()}</span>
            </button>
            
            <Link
              href="/admin/login"
              className="hidden sm:flex w-11 h-11 md:w-12 md:h-12 items-center justify-center rounded-lg md:rounded-xl bg-black/5 border border-black/5 text-black/20 hover:text-black transition-all duration-500"
            >
              <ShieldCheck size={16} />
            </Link>
          </div>
        </motion.div>
      </div>

      {/* Floating Logo Top Left (Desktop Only) */}
      <div className="fixed top-8 left-8 pointer-events-auto hidden lg:block">
        <Logo className="scale-90" />
      </div>
    </>
  );
}
