'use client';

import { motion, useMotionValue, useSpring, useTransform, AnimatePresence } from 'framer-motion';
import { useRef, useState } from 'react';
import Link from 'next/link';

interface DockItemProps {
  icon: React.ReactNode;
  label: string;
  href: string;
  active?: boolean;
  mouseX: any;
  magnification: number;
  distance: number;
  baseItemSize: number;
}

function DockItem({ 
  icon, 
  label, 
  href, 
  active, 
  mouseX, 
  magnification, 
  distance, 
  baseItemSize 
}: DockItemProps) {
  const ref = useRef<HTMLDivElement>(null);
  const [isHovered, setIsHovered] = useState(false);

  const mouseDistance = useTransform(mouseX, (val: number) => {
    const rect = ref.current?.getBoundingClientRect() ?? { x: 0, width: baseItemSize };
    return val - rect.x - rect.width / 2;
  });

  const springConfig = { mass: 0.1, stiffness: 150, damping: 12 };
  const targetSize = useTransform(mouseDistance, [-distance, 0, distance], [baseItemSize, magnification, baseItemSize]);
  const size = useSpring(targetSize, springConfig);

  return (
    <div className="relative flex flex-col items-center">
      <AnimatePresence>
        {isHovered && (
          <motion.div
            initial={{ opacity: 0, y: 10, x: '-50%' }}
            animate={{ opacity: 1, y: -10, x: '-50%' }}
            exit={{ opacity: 0, y: 10, x: '-50%' }}
            className="absolute -top-10 left-1/2 px-2.5 py-1 bg-gray-950/90 border border-white/10 rounded-lg text-[9px] font-black uppercase tracking-[0.2em] text-white backdrop-blur-md z-50 whitespace-nowrap shadow-2xl pointer-events-none"
          >
            {label}
          </motion.div>
        )}
      </AnimatePresence>
      
      <Link href={href}>
        <motion.div
          ref={ref}
          style={{ width: size, height: size }}
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
          className={`flex items-center justify-center rounded-xl md:rounded-2xl border transition-all duration-500 relative
            ${active 
              ? 'bg-brand-blue/10 border-brand-blue/20 text-brand-blue shadow-[0_10px_20px_rgba(34,211,238,0.1)]' 
              : 'bg-black/5 border-black/5 text-black/30 hover:bg-black/10 hover:text-black'
            }`}
        >
          {icon}
          {active && (
            <motion.div 
              layoutId="dock-dot"
              className="absolute -bottom-1 w-1 h-1 bg-brand-blue rounded-full"
            />
          )}
        </motion.div>
      </Link>
    </div>
  );
}

export default function Dock({
  items,
  className = "",
  magnification = 65,
  distance = 140,
  baseItemSize = 44,
}: {
  items: { icon: React.ReactNode; label: string; href: string; active?: boolean }[];
  className?: string;
  magnification?: number;
  distance?: number;
  baseItemSize?: number;
}) {
  const mouseX = useMotionValue(Infinity);

  return (
    <motion.div
      onMouseMove={(e) => mouseX.set(e.pageX)}
      onMouseLeave={() => mouseX.set(Infinity)}
      className={`flex items-end gap-2 md:gap-3 px-3 md:px-4 py-2 md:py-3 rounded-2xl md:rounded-[2rem] bg-white/80 backdrop-blur-3xl border border-black/5 shadow-[0_20px_50px_rgba(0,0,0,0.05)] transition-all duration-300 ${className}`}
    >
      {items.map((item, index) => (
        <DockItem
          key={index}
          {...item}
          mouseX={mouseX}
          magnification={magnification}
          distance={distance}
          baseItemSize={baseItemSize}
        />
      ))}
    </motion.div>
  );
}
